package com.hogaria.service;
import com.hogaria.entity.*;import com.hogaria.repository.*;import org.junit.jupiter.api.Test;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import java.math.BigDecimal;import java.time.LocalDate;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class)
class DashboardServiceTest { @Mock FinancialProfileRepository profileRepository; @Mock MoneyTransactionRepository transactionRepository; @Mock CategoryRepository categoryRepository; @InjectMocks DashboardService service;
@Test void computesSummary(){var u=UUID.randomUUID();var p=UUID.randomUUID();when(profileRepository.findByIdAndUserId(p,u)).thenReturn(Optional.of(new FinancialProfile())); var c1=UUID.randomUUID(); var c2=UUID.randomUUID(); when(categoryRepository.findAllById(any())).thenReturn(List.of(Category.builder().id(c1).name("Sueldo").type(Category.Type.INCOME).build(),Category.builder().id(c2).name("Renta").type(Category.Type.FIXED_EXPENSE).build())); when(transactionRepository.findByProfileIdAndBudgetDateBetween(eq(p),any(),any())).thenReturn(List.of(MoneyTransaction.builder().profileId(p).categoryId(c1).movementType(MoneyTransaction.MovementType.INCOME).amount(new BigDecimal("100")).status(MoneyTransaction.Status.CONFIRMED).budgetDate(LocalDate.now()).build(),MoneyTransaction.builder().profileId(p).categoryId(c2).movementType(MoneyTransaction.MovementType.EXPENSE).amount(new BigDecimal("50")).status(MoneyTransaction.Status.CONFIRMED).budgetDate(LocalDate.now()).build())); var r=service.getMonthlySummary(u,p,2026,5); assertEquals(new BigDecimal("100"),r.monthlyBalance().totalIncome());}
@Test void zeroIncomeNoCrash(){var u=UUID.randomUUID();var p=UUID.randomUUID();when(profileRepository.findByIdAndUserId(p,u)).thenReturn(Optional.of(new FinancialProfile())); when(transactionRepository.findByProfileIdAndBudgetDateBetween(eq(p),any(),any())).thenReturn(List.of()); when(categoryRepository.findAllById(any())).thenReturn(List.of()); assertEquals(0,service.getMonthlySummary(u,p,2026,5).fiftyThirtyTwenty().fixedPercent().signum());}
@Test void criticalWhenNegative(){var u=UUID.randomUUID();var p=UUID.randomUUID();var c=UUID.randomUUID();when(profileRepository.findByIdAndUserId(p,u)).thenReturn(Optional.of(new FinancialProfile())); when(categoryRepository.findAllById(any())).thenReturn(List.of(Category.builder().id(c).type(Category.Type.FIXED_EXPENSE).name("x").build())); when(transactionRepository.findByProfileIdAndBudgetDateBetween(eq(p),any(),any())).thenReturn(List.of(MoneyTransaction.builder().profileId(p).categoryId(c).movementType(MoneyTransaction.MovementType.EXPENSE).amount(new BigDecimal("10")).status(MoneyTransaction.Status.CONFIRMED).budgetDate(LocalDate.now()).build())); assertEquals("CRITICAL",service.getMonthlySummary(u,p,2026,5).financialHealth());}
}
